import React, { useState } from 'react';
import SyntaxHighlighter from 'react-syntax-highlighter';
import { atomOneDark, atomOneLight } from 'react-syntax-highlighter/dist/esm/styles/hljs';
import '../../styles/message-renderer.css';

const MessageRenderer = ({ content, theme, contentType = 'general' }) => {
  const [copiedCode, setCopiedCode] = useState('');
  const codeStyle = theme === 'dark' ? atomOneDark : atomOneLight;

  const parseMarkdown = (text) => {
    const lines = text.split('\n');
    const elements = [];
    let currentBlock = null;
    let codeLang = '';
    let codeLines = [];

    // ✅ FIXED: Use a constant to avoid string literal issues
    const CODE_BLOCK_MARKER = '```';

    lines.forEach((line, index) => {
      // ✅ FIXED: Using variable instead of string literal
      if (line.startsWith(CODE_BLOCK_MARKER)) {
        if (currentBlock === null) {
          currentBlock = index;
          codeLang = line.slice(3).trim() || 'text';
          codeLines = [];
          return;
        } else {
          const codeString = codeLines.join('\n');
          elements.push(
            <div key={`code-${currentBlock}`} className="code-block-container">
              <div className="code-header">
                <span className="code-language">{codeLang}</span>
                <button
                  className="copy-code-btn"
                  onClick={() => copyToClipboard(codeString)}
                  title="Copy code"
                >
                  {copiedCode === codeString ? '✅' : '📋'}
                </button>
              </div>
              <SyntaxHighlighter
                language={codeLang}
                style={codeStyle}
                customStyle={{
                  margin: 0,
                  borderRadius: '0 0 8px 8px',
                  fontSize: '14px'
                }}
              >
                {codeString}
              </SyntaxHighlighter>
            </div>
          );
          currentBlock = null;
          codeLang = '';
          codeLines = [];
          return;
        }
      }

      // Handle content inside code blocks
      if (currentBlock !== null) {
        codeLines.push(line);
        return;
      }

      // Handle headers
      if (line.startsWith('## ')) {
        elements.push(
          <h3 key={`header-${index}`} className="message-header">
            {line.slice(3).trim()}
          </h3>
        );
        return;
      }

      if (line.startsWith('### ')) {
        elements.push(
          <h4 key={`subheader-${index}`} className="message-subheader">
            {line.slice(4).trim()}
          </h4>
        );
        return;
      }

      // Handle emoji headers for Nexus AI format
      if (line.startsWith('🔧 ') || line.startsWith('🚀 ') || line.startsWith('💡 ')) {
        elements.push(
          <h3 key={`emoji-header-${index}`} className="message-header">
            {line.trim()}
          </h3>
        );
        return;
      }

      // Handle bullet points
      if (line.trim().startsWith('* ') || line.trim().startsWith('- ')) {
        const bulletText = line.replace(/^[-*]\s*/, '').trim();
        if (bulletText) {
          elements.push(
            <div key={`bullet-${index}`} className="bullet-point">
              <span className="bullet-icon">• </span>
              <span className="bullet-text">{bulletText}</span>
            </div>
          );
        }
        return;
      }

      // Handle regular text
      if (line.trim() !== '') {
        elements.push(
          <p key={`text-${index}`} className="message-text">
            {line.trim()}
          </p>
        );
      } else {
        elements.push(
          <div key={`space-${index}`} className="message-spacer"></div>
        );
      }
    });

    return elements;
  };

  const copyToClipboard = async (text) => {
    try {
      await navigator.clipboard.writeText(text);
      setCopiedCode(text);
      setTimeout(() => setCopiedCode(''), 2000);
    } catch (err) {
      console.error('Failed to copy code:', err);
    }
  };

  return (
    <div className="message-content-wrapper">
      <div className={`message-content ${contentType}-content`}>
        {parseMarkdown(content)}
      </div>
    </div>
  );
};

export default MessageRenderer;
